/**
 * LogoCloudPropertyPanel
 * Author: generated by Amazon Q
 * Created: 2025-01-27
 * Purpose: Property panel for logo-cloud section with image, SVG, and Font Awesome icon support
 */

'use client';

import React, { useState } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { IconButton, type IconConfig } from '@/components/ui/IconPicker';
import { MediaUpload } from '@/components/ui/MediaUpload';

interface LogoCloudPropertyPanelProps {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

const inputCls = 'w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm';
const textareaCls = inputCls + ' resize-none';

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">{label}</label>
      {children}
    </div>
  );
}

function Collapsible({ title, badge, children, defaultOpen = false }: {
  title: string; badge?: string; children: React.ReactNode; defaultOpen?: boolean;
}) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="border border-gray-200 dark:border-gray-600 rounded-lg overflow-hidden">
      <button type="button" onClick={() => setOpen(o => !o)}
        className="w-full flex items-center justify-between px-3 py-2.5 bg-gray-50 dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600 transition-colors text-left">
        <span className="text-sm font-medium text-gray-800 dark:text-white flex items-center gap-2">
          {title}
          {badge && <span className="text-xs bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-2 py-0.5 rounded-full">{badge}</span>}
        </span>
        <span className={`text-gray-400 text-xs transition-transform ${open ? 'rotate-90' : ''}`}>▶</span>
      </button>
      {open && <div className="p-3 space-y-3 bg-white dark:bg-gray-800">{children}</div>}
    </div>
  );
}

export function LogoCloudPropertyPanel({ section, onUpdate }: LogoCloudPropertyPanelProps) {
  const data = section.data as any;
  const update = (patch: Record<string, any>) => onUpdate({ data: { ...data, ...patch } });

  const updateLogo = (idx: number, updates: any) => {
    const logos = [...(data.logos ?? [])];
    logos[idx] = { ...logos[idx], ...updates };
    update({ logos });
  };

  const addLogo = () => {
    update({ logos: [...(data.logos ?? []), { name: 'Company', imageUrl: '', alt: '', iconName: '', iconConfig: null }] });
  };

  const removeLogo = (idx: number) => {
    update({ logos: (data.logos ?? []).filter((_: any, i: number) => i !== idx) });
  };

  const moveLogo = (idx: number, dir: -1 | 1) => {
    const logos = [...(data.logos ?? [])];
    const t = idx + dir;
    if (t < 0 || t >= logos.length) return;
    [logos[idx], logos[t]] = [logos[t], logos[idx]];
    update({ logos });
  };

  return (
    <div className="space-y-4">
      {/* Header */}
      <Collapsible title="Section Header" defaultOpen>
        <Field label="Title">
          <input className={inputCls} value={data.title ?? ''} onChange={e => update({ title: e.target.value })} />
        </Field>
        <Field label="Subtitle">
          <textarea className={textareaCls} rows={2} value={data.subtitle ?? ''} onChange={e => update({ subtitle: e.target.value })} />
        </Field>
      </Collapsible>

      {/* Logos */}
      <Collapsible title="Logos" badge={`${(data.logos ?? []).length}`} defaultOpen>
        <div className="space-y-3 max-h-[600px] overflow-y-auto">
          {(data.logos ?? []).map((logo: any, idx: number) => (
            <div key={idx} className="border border-gray-300 dark:border-gray-600 rounded-lg p-3 space-y-3 bg-gray-50 dark:bg-gray-700/50">
              <div className="flex items-center justify-between">
                <span className="text-xs font-semibold text-gray-700 dark:text-gray-300">Logo #{idx + 1}: {logo.name}</span>
                <div className="flex gap-1">
                  <button type="button" onClick={() => moveLogo(idx, -1)} disabled={idx === 0} className="px-2 py-1 text-xs bg-gray-200 dark:bg-gray-600 rounded disabled:opacity-30">↑</button>
                  <button type="button" onClick={() => moveLogo(idx, 1)} disabled={idx === (data.logos ?? []).length - 1} className="px-2 py-1 text-xs bg-gray-200 dark:bg-gray-600 rounded disabled:opacity-30">↓</button>
                  <button type="button" onClick={() => removeLogo(idx)} className="px-2 py-1 text-xs bg-red-100 dark:bg-red-900/30 text-red-600 rounded">🗑</button>
                </div>
              </div>

              <Field label="Company Name">
                <input className={inputCls} value={logo.name ?? ''} onChange={e => updateLogo(idx, { name: e.target.value })} placeholder="e.g. SAP, Oracle" />
              </Field>

              <Field label="Alt Text">
                <input className={inputCls} value={logo.alt ?? ''} onChange={e => updateLogo(idx, { alt: e.target.value })} placeholder="Accessibility description" />
              </Field>

              {/* Logo Type Selection */}
              <div className="border-t border-gray-300 dark:border-gray-600 pt-3">
                <p className="text-xs font-semibold text-gray-700 dark:text-gray-300 mb-2">Logo Display (choose one):</p>

                {/* Option 1: Font Awesome Icon */}
                <Collapsible title="Font Awesome Icon" badge={logo.iconConfig ? 'Active' : ''}>
                  <IconButton
                    value={logo.iconConfig}
                    onChange={(icon: IconConfig | null) => updateLogo(idx, { iconConfig: icon, imageUrl: '', iconName: '' })}
                    placeholder="Select Font Awesome icon"
                  />
                  {logo.iconConfig && (
                    <button
                      type="button"
                      onClick={() => updateLogo(idx, { iconConfig: null })}
                      className="w-full mt-2 py-1.5 text-xs text-red-500 border border-dashed border-red-300 dark:border-red-800 rounded hover:bg-red-50 dark:hover:bg-red-900/20"
                    >
                      Clear Icon
                    </button>
                  )}
                </Collapsible>

                {/* Option 2: Image Upload */}
                <Collapsible title="Image Upload" badge={logo.imageUrl ? 'Active' : ''}>
                  <MediaUpload
                    src={logo.imageUrl ?? ''}
                    alt={logo.alt || logo.name}
                    width={200}
                    height={80}
                    onMediaChange={(src: string) => updateLogo(idx, { imageUrl: src, iconConfig: null, iconName: '' })}
                    objectFit="contain"
                    showUploadButton
                    uploadButtonText="Upload Logo"
                    acceptedTypes="image/*"
                  />
                  {logo.imageUrl && (
                    <button
                      type="button"
                      onClick={() => updateLogo(idx, { imageUrl: '' })}
                      className="w-full mt-2 py-1.5 text-xs text-red-500 border border-dashed border-red-300 dark:border-red-800 rounded hover:bg-red-50 dark:hover:bg-red-900/20"
                    >
                      Remove Image
                    </button>
                  )}
                </Collapsible>

                {/* Option 3: Font Awesome Brands (Legacy - by name) */}
                <Collapsible title="Font Awesome Brands (Legacy)" badge={logo.iconName ? 'Active' : ''}>
                  <Field label="Icon Name (e.g. microsoft, slack, aws)">
                    <input
                      className={inputCls}
                      value={logo.iconName ?? ''}
                      onChange={e => updateLogo(idx, { iconName: e.target.value, iconConfig: null, imageUrl: '' })}
                      placeholder="e.g. microsoft, slack, aws"
                    />
                  </Field>
                  <p className="text-[10px] text-gray-500 dark:text-gray-400 mt-1">
                    ⚠️ Legacy method. Use Font Awesome Icon picker above for better control.
                  </p>
                </Collapsible>
              </div>
            </div>
          ))}
        </div>

        <button
          type="button"
          onClick={addLogo}
          className="w-full py-2 border border-dashed border-blue-300 dark:border-blue-700 rounded-md text-sm text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 font-medium"
        >
          + Add Logo
        </button>
      </Collapsible>
    </div>
  );
}
